#include <stdio.h>
#include <stdlib.h>
#define MAXN 500
#define MAXM 2000

// Structure to represent a graph
typedef struct {
    int n, m;
    int **edges;
    double *f;
} Graph;

// Function to create a graph
Graph *createGraph(int n, int m) {
    Graph *graph = (Graph *)malloc(sizeof(Graph));
    graph->n = n;
    graph->m = m;
    graph->edges = (int **)malloc(m * sizeof(int *));
    for (int i = 0; i < m; i++) {
        graph->edges[i] = (int *)malloc(2 * sizeof(int));
    }
    graph->f = (double *)malloc(n * sizeof(double));
    return graph;
}

// Function to detect cycles and check if the input function is a generalized independent set
void checkCycle(Graph *graph) {
    int *visited = (int *)malloc(graph->n * sizeof(int));
    for (int i = 0; i < graph->n; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < graph->n; i++) {
        if (!visited[i]) {
            dfs(graph, i, visited, -1);
        }
    }
    free(visited);
}

// Function to perform DFS and detect cycles
void dfs(Graph *graph, int node, int *visited, int parent) {
    visited[node] = 1;
    for (int i = 0; i < graph->m; i++) {
        if (graph->edges[i][0] == node) {
            int neighbor = graph->edges[i][1];
            if (!visited[neighbor]) {
                dfs(graph, neighbor, visited, node);
            } else if (neighbor != parent) {
                // Cycle detected
                double sum = 0;
                int cycleSize = 0;
                int *cycle = (int *)malloc(graph->n * sizeof(int));
                int index = 0;
                int currentNode = node;
                while (currentNode != neighbor) {
                    cycle[index++] = currentNode;
                    currentNode = visited[currentNode];
                }
                cycle[index++] = neighbor;
                cycleSize = index;
                for (int j = 0; j < cycleSize; j++) {
                    sum += graph->f[cycle[j]];
                }
                if (sum > (double)(cycleSize / 2)) {
                    printf("Bad Cycle: ");
                    for (int j = 0; j < cycleSize; j++) {
                        printf("%d ", cycle[j]);
                    }
                    printf("-1\n");
                    return;
                }
                free(cycle);
            }
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n, m;
        scanf("%d %d", &n, &m);
        Graph *graph = createGraph(n, m);
        for (int i = 0; i < n; i++) {
            scanf("%lf", &graph->f[i]);
        }
        for (int i = 0; i < m; i++) {
            scanf("%d %d", &graph->edges[i][0], &graph->edges[i][1]);
        }
        checkCycle(graph);
        printf("Ok\n");
    }
    return 0;
}

