function dfs(graph, node, visited, parent) {
    visited[node] = 1;
    for (let i = 0; i < graph.m; i++) {
        if (graph.edges[i][0] === node) {
            let neighbor = graph.edges[i][1];
            if (visited[neighbor] === 0) {
                dfs(graph, neighbor, visited, node);
